values
  ('686', '우무오미자냉화채', '후식', '오미자 10g, 물 200g, 올리고당 14g, 우무묵 20g', '["오미자","물","올리고당","우무묵"]'::jsonb, ARRAY['45780aea-56ef-4a8b-875a-65e3e61c4a78','94786475-832c-4f97-aab7-bf6fbbe2236b','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"오미자를 헹궈 따뜻한 물에 담가 12시간 우린다.","imageUrl":null},{"step":2,"text":"우려낸 오미자물을 면보에 거른다.","imageUrl":null},{"step":3,"text":"오미자 국물 1컵에 올리고당을 넣어 감미한다.","imageUrl":null},{"step":4,"text":"우무를 곱게 채 썰거나 모양 틀로 찍어낸다.","imageUrl":null},{"step":5,"text":"오미자 국물을 살짝 얼려 믹서에 갈아 슬러쉬를 만든다.","imageUrl":null},{"step":6,"text":"오미자 슬러쉬에 우무를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102047_1416273647602.jpg', 71.3, 14.4, 1.65, 0.88, 17),
  ('688', '포도호두스무디', '후식', '얼린포도알 80g, 오미자액 15g, 호상요구르트 30g, 깐호두 5g', '["얼린포도알","오미자액","호상요구르트","깐호두"]'::jsonb, ARRAY['45780aea-56ef-4a8b-875a-65e3e61c4a78']::uuid[], '[{"step":1,"text":"포도를 씻는다.","imageUrl":null},{"step":2,"text":"포도 껍질을 까고, 포도알을 떼어 낸다.","imageUrl":null},{"step":3,"text":"포도알은 뚜껑이 있는 통에 담아 냉동고에 얼린다.","imageUrl":null},{"step":4,"text":"얼린 포도알에 오미자액과 호상요구르트를 넣고 믹서에 갈아 스무디를 만든다.","imageUrl":null},{"step":5,"text":"호두는 칼로 굵게 다진다.","imageUrl":null},{"step":6,"text":"다진 호두는 스무디 위에 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102113_1416273673197.jpg', 159.8, 24.1, 4.5, 5.8, 26.5),
  ('689', '전복영양밥과 부추양념장', '밥', '전복영양밥 : 쌀 90g, 전복살 40g, 양송이 버섯 13g, 표고버섯 15g, 당근 15g, 건다시마 5g,물 400g , 다시마국물 5g, 부추 5g, 간장 5g, 실파 2.5g, 다진 마늘 2.5g, 참기름 0.5g, 통깨 0.5g', '["전복영양밥 : 쌀","전복살","양송이 버섯","표고버섯","당근","건다시마","물","다시마국물","부추","간장","실파","다진 마늘","참기름","통깨"]'::jsonb, ARRAY['48a4fd5a-e4f6-467b-9e3f-445334e0ee04','66458b1b-c92f-43fa-8eba-e428892ce88a','e38c12a7-43cb-421a-a36e-7ef0d32517fa','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','94786475-832c-4f97-aab7-bf6fbbe2236b','a4c37075-c03b-47bb-8aed-5e907620f5d2','058648c3-fd8e-476d-952f-b15dc67f1877','f175019d-5a93-4cd4-aabc-e7e79445f15a','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"물 2컵에 건다시마를 넣어 다시마국물을 1컵 반 정도를 낸다.","imageUrl":null},{"step":2,"text":"우린 다시마와 전복살은 잘게 다진다.","imageUrl":null},{"step":3,"text":"표고버섯, 양송이버섯, 당근은 0.5~0.7cm 주사위모양으로 썬다.","imageUrl":null},{"step":4,"text":"쌀은 씻어 2와 3을 넣고 다시마국물 1컵 반을 부어 30분 정도 불린 후 밥을 짓는다.","imageUrl":null},{"step":5,"text":"부추와 실파는 다지고 참기름, 다진 마늘, 통깨, 다시마국물, 간장을 넣어 양념장을 만든다.","imageUrl":null},{"step":6,"text":"전복영양밥과에 부추양념장을 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102114_1416273674091.jpg', 387.2, 77.5, 12.8, 1.9, 459.9),
  ('690', '근대쌈밥과 멸치견과류쌈장', '밥', '근대쌈밥 : 쌀 70g, 현미 10g, 보리쌀 10g, 근대 50g, 물 400g, 국멸치 2g, 건다시마 2.5g, , 다시마국물 10g, 양파 3g, 된장 2.5g, 파 2.5g, 고추장 2.5g, 잔멸치 2.5g, 호두 2.5g, 잣 2.5g, 땅콩 2.5g, 다진 마늘 2.5g, 매실액 2.5g', '["근대쌈밥 : 쌀","현미","보리쌀","근대","물","국멸치","건다시마","다시마국물","양파","된장","파","고추장","잔멸치","호두","잣","땅콩","다진 마늘","매실액"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','94786475-832c-4f97-aab7-bf6fbbe2236b','dd2eee03-8bbf-44ff-8a7f-ed1443986711','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','a4c37075-c03b-47bb-8aed-5e907620f5d2','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','392236b1-82e9-4e38-bd12-6a53b80bf463','4b410642-7bf9-45ad-9055-e7d9a34edaa1','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','7651578f-1206-499d-a04c-15f034d4cae2','bbbbd533-8922-4dac-9e4c-cd93ea710c92','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','fc6e31ce-388e-45cd-956b-b238b9134eb1','02fd7135-0ec3-49ec-82e3-390536ab2cf5']::uuid[], '[{"step":1,"text":"물 2/3컵에 국멸치와 건다시마를 넣고 끓여 국물을 내면서 이 열로 근대를 삼발이에 놓고 찐다.","imageUrl":null},{"step":2,"text":"국물 우린 다시마를 잘게 썰어 쌀, 현미, 보리쌀과 함께 잡곡밥을 짓는다.","imageUrl":null},{"step":3,"text":"잔멸치는 기름을 두르지 않고 팬에 살짝 볶아 다지고 견과류도 칼로 다진다.","imageUrl":null},{"step":4,"text":"양파와 파를 다진다.","imageUrl":null},{"step":5,"text":"고추장, 된장, 견과류, 양파, 다진 마늘, 매실액, 파, 멸치다시마국물을 섞어 멸치견과류쌈장을 만든다.","imageUrl":null},{"step":6,"text":"근대위에 밥을 약 30g(1숟가락)정도 올리고 멸치견과류쌈장 5g 가량 넣어 근대잎으로 싼다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102115_1416273675090.jpg', 407.3, 76.1, 11.7, 6.1, 456.8),
  ('428', '장어조림', '반찬', '장어 150g, 깻잎 10g, 청고추17g, 홍고추 17g, 양파 60g, 생강 15g
양념장 : 맛간장 25g, 올리고당 15g, 청주 15g, 참기름 15g, 흰후추 1g
통깨 5g, 통마늘 20g, 대파 10g', '["장어","깻잎","청고추","홍고추","양파","생강","양념장 : 맛간장","올리고당","청주","참기름","흰후추","통깨","통마늘","대파"]'::jsonb, ARRAY['d9d44d6d-6648-409b-857c-15bf7b42f0df','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','30b5d53c-d247-4f04-9b50-c0f728e65cf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"장어는 한입 크기로 잘라서 흰 후추와 청주를\r\n뿌려 재워준다.","imageUrl":null},{"step":2,"text":"깻잎은 채를 썰어서 냉수에 담가 물기를\r\n빼준다.","imageUrl":null},{"step":3,"text":"생강, 마늘은 편으로 썰어주고 양파, 청고추,\r\n홍고추는 어슷하게 잘라준다.","imageUrl":null},{"step":4,"text":"참기름을 뺀 양념장 재료에 편마늘과 다진대파를\r\n넣어서 양념장을 만들어준다.","imageUrl":null},{"step":5,"text":"만들어진 양념장 1/2에 장어를 넣고 졸여준다.","imageUrl":null},{"step":6,"text":"나머지 양념장에 준비된 채소를 넣어 볶아주다\r\n졸인 장어를 넣어 졸여주고 깻잎을 깔고\r\n완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00428_2.png', 190.1, 21, 14.1, 505, 1236.7),
  ('429', '통삼겹스테이크', '일품', '통삼겹 200g, 건로즈마리 1g, 로즈마리 2g, 올리브유 15g
