  ('381', '연어스테이크', '일품', '연어 150g, 건조다시마 사방 10cm 1장, 잎녹차 5g, 브로콜리 15g, 호두10g
귀리 20g, 쌀 20g, 미소된장 5g, 흰후추 1g, 화이트와인 15g,, 생크림 50g
수제조미료 10g, 닭육수 150g, 버터 5g', '["연어","건조다시마 사방","잎녹차","브로콜리","호두","귀리","쌀","미소된장","흰후추","화이트와인","생크림","수제조미료","닭육수","버터"]'::jsonb, ARRAY['35db7cf0-556e-49d8-b6d2-f6e1b1e12e16','9bf64924-ce53-42bb-849e-7294416e95d6','7651578f-1206-499d-a04c-15f034d4cae2','c15a4a69-31ab-450d-943a-2a7bb2230857','a5bc0b46-0192-496a-b429-d2cb90b2bca9','392236b1-82e9-4e38-bd12-6a53b80bf463','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','e16eaf50-ebd3-4933-a774-3ce6fc92593f','af187077-b7f6-4b0e-9e99-f844f6359ac2','a4c37075-c03b-47bb-8aed-5e907620f5d2','7aabd532-361f-4240-aa33-6bfa1be4bc4e']::uuid[], '[{"step":1,"text":"연어는 불려준 다시마에 싸주어 24시간 염지\r\n시켜준다.","imageUrl":null},{"step":2,"text":"잎 녹차는 물에 불려준다.","imageUrl":null},{"step":3,"text":"뒤 수분을 빼주고 팬에 올려서 연어를 약불\r\n에서 구워내 준다.","imageUrl":null},{"step":4,"text":"브로콜리, 호두도 먹기 좋게 잘라준다.","imageUrl":null},{"step":5,"text":"귀리와 쌀은 1시간정도 불려준다.","imageUrl":null},{"step":6,"text":"닭 육수와 미소된장을 넣어 볶아주다가 불린\r\n쌀을 넣어 볶아주어 리조또를 완성하고 접시에\r\n리조또를 담고 구운 연어를 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00381_2.png', 487.8, 31.1, 23.3, 26.1, 362.3),
  ('382', '웰빙꼬치', '반찬', '닭가슴살 150g, 자숙새우 100g, 소라살 100g, 방울토마토 80g
단호박 100g, 대파 50g, 2가지색 파프리카 100g
양파 100g, 흰 후추 2g, 레드와인 30g, 다진 마늘 15g, 올리브오일 30g, 통후추 3g
소스 : 발사믹 식초 100g, 설탕 30g, 버터 30g', '["닭가슴살","자숙새우","소라살","방울토마토","단호박","대파","양파","흰 후추","레드와인","다진 마늘","올리브오일","통후추","소스 : 발사믹 식초","설탕","버터"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','98d652af-a6d6-440c-9653-e22fc5d47d88','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','e16eaf50-ebd3-4933-a774-3ce6fc92593f','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','06e6f3e7-0293-469d-a338-11a610f3e71b','7aabd532-361f-4240-aa33-6bfa1be4bc4e']::uuid[], '[{"step":1,"text":"닭가슴살과 단호박은 사방 2.5cm 크기로\r\n잘라준다.","imageUrl":null},{"step":2,"text":"양파 2가지, 색파프리카, 대파는 닭 크기와\r\n비슷하게 잘라준다.","imageUrl":null},{"step":3,"text":"닭가슴살과 소라살은 통후추, 올리브오일에\r\n재워준다.","imageUrl":null},{"step":4,"text":"소스를 만들어준다.","imageUrl":null},{"step":5,"text":"모든 재료를 꼬치에 꽂는다.","imageUrl":null},{"step":6,"text":"꼬치를 팬에 구워주면서 소스를 발라준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00382_2.png', 125.5, 15.1, 11.8, 2, 60.5),
  ('383', '매운닭날개구이', '반찬', '닭날개 100g, 감자 80g, 방울토마토 100g, 브로콜리 30g
마늘 15g, 양파 50g, 버터 15g, 후추 1g, 황설탕 5g
고춧가루 5g, 레드와인 30g, 멕시코고추 1g', '["닭날개","감자","방울토마토","브로콜리","마늘","양파","버터","후추","황설탕","고춧가루","레드와인","멕시코고추"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','9bf64924-ce53-42bb-849e-7294416e95d6','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','7aabd532-361f-4240-aa33-6bfa1be4bc4e','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','06e6f3e7-0293-469d-a338-11a610f3e71b','84104c49-0af4-4323-a56b-b67002a422d9','e16eaf50-ebd3-4933-a774-3ce6fc92593f']::uuid[], '[{"step":1,"text":"닭날개를 멕시코고추와 고추가루에 설탕,\r\n다진마늘, 후추를 넣어 밑간을 해준다.","imageUrl":null},{"step":2,"text":"감자는 먹기 좋게 썰어 뜨거운 물에 70%\r\n정도 익혀준다.","imageUrl":null},{"step":3,"text":"감자는 데쳐 낸 후 버터에 볶아준다.","imageUrl":null},{"step":4,"text":"브로콜리는 데치고, 사과와 토마토는 잘게\r\n잘라준다.","imageUrl":null},{"step":5,"text":"냄비에 다진마늘과 다진양파를 볶아주다\r\n토마토를 넣어 소스를 만들어준다.","imageUrl":null},{"step":6,"text":"닭날개를 팬에 구워주고 감자와 샐러드를\r\n곁들여 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00383_2.png', 285, 22, 17, 14.3, 433.9),
  ('384', '웰빙카레죽', '반찬', '카레가루 45g, 귀리밥 200g, 닭가슴살 150g, 애호박 25g
감자 60g, 양파 60g, 방울토마토 100g
마늘 100g, 버터 15g, 칵테일새우 30g', '["카레가루","귀리밥","닭가슴살","애호박","감자","양파","방울토마토","마늘","버터","칵테일새우"]'::jsonb, ARRAY['495b9f1e-aa3b-4506-9bb8-feb0a493901e','c15a4a69-31ab-450d-943a-2a7bb2230857','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','20894da1-739d-4d52-b5fe-4943bd3492d5','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','fc6e31ce-388e-45cd-956b-b238b9134eb1','7aabd532-361f-4240-aa33-6bfa1be4bc4e','6f10b4ad-53a2-4a07-ba89-19a6b074373d']::uuid[], '[{"step":1,"text":"카레가루를 물에 풀어서 30분 정도 숙성\r\n시켜준다.","imageUrl":null},{"step":2,"text":"닭가슴살은 사방 1cm 크기로 잘라주고,\r\n칵테일새우도 세척해 준비한다.","imageUrl":null},{"step":3,"text":"알 마 늘 , 감자는 사 방 1 c m 길이로 잘라\r\n물 400g에 먼저 익혀준다.","imageUrl":null},{"step":4,"text":"방울토마토, 애호박은 사방 1cm 크기로\r\n썰어준다.","imageUrl":null},{"step":5,"text":"끓고 있는 냄비에 풀어 놓은 카레가루를 섞어\r\n다시 끓여준다.","imageUrl":null},{"step":6,"text":"양파는 사방 1cm 길이로 잘라주고 끓고 있는\r\n카레에 양파, 방울토마토, 애호박을 넣고\r\n끓여 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00384_2.png', 210.4, 33.7, 5.1, 6.1, 351),
  ('2963', '닭가슴살 두부선', '반찬', '닭고기(가슴살) 50g, 두부 120g, 비트 10g, 시금치 10g, 베이비채소 1g, 마늘 2g, 참기름 1.5g, 흑임자 3g, 플레인요거트 15g, 식초 0.5g, 설탕 1g, 소금 0.2g', '["닭고기","두부","비트","시금치","베이비채소","마늘","참기름","흑임자","플레인요거트","식초","설탕","소금"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','4566cac5-9166-4c0d-906a-bfc7360f8f5b','524e1b82-1f81-4648-b50c-441404a06786','9a7f4da6-531b-4478-89ff-d73beafcad1b','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','bb41a88a-ea2b-4830-876d-91fe7f640296','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"닭가슴살, 두부, 소금을 믹서에 간다.","imageUrl":null},{"step":2,"text":"1에 간 마늘과 소금, 참기름을 섞는다.","imageUrl":null},{"step":3,"text":"반죽 1/3은 비트물, 1/3은 시금치물을 넣어 색을 입힌다.","imageUrl":null},{"step":4,"text":"틀에 반죽을 층층이 쌓아 모양을 만든 뒤 오븐에 찐다.","imageUrl":null},{"step":5,"text":"흑임자가루, 플레인요거트, 식초, 설탕을 섞어 드레싱을 만든다.","imageUrl":null},{"step":6,"text":"접시에 담고 소스와 베이비채소를 얹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408102916_1554686956344.jpg', 94.34, 1.13, 14.4, 3.58, 17.24),
  ('2964', '단호박 마전', '반찬', '단호박 70g, 마 20g, 밀가루 5g, 찹쌀가루 5g, 건대추 1g, 소금 0.3g', '["단호박","마","밀가루","찹쌀가루","건대추","소금"]'::jsonb, ARRAY['98d652af-a6d6-440c-9653-e22fc5d47d88','a988ffbb-92c3-4c68-8cea-a2f10c329015','aab3b0b9-d346-4697-a1c8-1b1530153788','4cb11562-015f-4ab5-969f-0ea8483a0b42','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"단호박을 잘게 다진다.","imageUrl":null},{"step":2,"text":"마를 0.3cm 두께로 썰어 뜨거운 물에 데친다.","imageUrl":null},{"step":3,"text":"잘게 다진 단호박에 밀가루와 찹쌀가루, 물, 소금을 넣어 반죽한다.","imageUrl":null},{"step":4,"text":"프라이팬에 식용유를 두르고 반죽을 두른다.","imageUrl":null},{"step":5,"text":"두른 반죽 가운데 마를 올려 부친다.","imageUrl":null},{"step":6,"text":"먹기 좋게 담은 후 건대추를 고명으로 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408103439_1554687279859.jpg', 122.34, 16.58, 2.53, 5.1, 1.18),
  ('3010', '완두콩과 당근을 넣은 감자요거트 샐러드', '기타', '완두콩 10g, 당근 10g, 감자 50g, 플레인요거트 20g', '["완두콩","당근","감자","플레인요거트"]'::jsonb, ARRAY['5fd34bed-4339-4fcc-9221-f082ce6ac652','e38c12a7-43cb-421a-a36e-7ef0d32517fa','20894da1-739d-4d52-b5fe-4943bd3492d5','bb41a88a-ea2b-4830-876d-91fe7f640296']::uuid[], '[{"step":1,"text":"완두콩을 삶아 건진다.","imageUrl":null},{"step":2,"text":"감자는 삶은 뒤 건져 껍질을 벗긴다.","imageUrl":null},{"step":3,"text":"감자가 뜨거울 때 곱게 으깬다.","imageUrl":null},{"step":4,"text":"당근을 잘게 다진다.","imageUrl":null},{"step":5,"text":"으깬 감자와 완두콩, 당근을 섞는다.","imageUrl":null},{"step":6,"text":"플레인요거트를 섞어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306030122_1678082482750.jpg', 44.3, 8.3, 2, 0.4, 25.5),
  ('3098', '무오색쌈', '반찬', '쌈무 10.5g, 쇠고기 4.5g, 달걀 2.4g, 당근 3.3g, 표고버섯 3.2g, 오이 7.8g, 연겨자 0.28g, 진간장 0.05g, 식초 0.57g, 참기름 0.14g, 깐마늘 0.3g, 설탕 0.1g, 통깨 0.01g, 소금 0.05g', '["쌈무","쇠고기","달걀","당근","표고버섯","오이","연겨자","진간장","식초","참기름","깐마늘","설탕","통깨","소금"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','c7d438a6-34d6-423f-905d-446b839e2f39','e38c12a7-43cb-421a-a36e-7ef0d32517fa','66458b1b-c92f-43fa-8eba-e428892ce88a','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','5b59cfae-1277-48af-99a6-833687e2da0b','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f','0c0ade94-cfd8-4104-b44c-40e942cac482','fc6e31ce-388e-45cd-956b-b238b9134eb1','06e6f3e7-0293-469d-a338-11a610f3e71b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"당근, 오이, 표고버섯은 5cm 길이로 가늘게 채썬다.","imageUrl":null},{"step":2,"text":"당근, 오이, 표고버섯은 각각 살짝 볶아내어 식혀둔다.","imageUrl":null},{"step":3,"text":"쇠고기는 간장, 설탕, 마늘, 참기름을 넣어 밑간하여 볶아낸다.","imageUrl":null},{"step":4,"text":"달걀은 얇게 지단을 부쳐 5cm 길이로 썬다.","imageUrl":null},{"step":5,"text":"연겨자, 식초, 마늘, 설탕, 깨를 넣어 소스를 만든다.","imageUrl":null},{"step":6,"text":"모든 재료를 소스에 버무린 다음 무쌈과 함께 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113150_1584412310801.JPG', 19.1, 1.1, 1.7, 0.9, 63.5),
  ('3099', '흑마늘견과류조림', '반찬', '통마늘 10g, 마카다미아 5g, 호두 5g, 아몬드 5g, 캐슈넛 2g, 땅콩 2g, 대두유 5g, 흑마늘진액 5g, 간장 2g, 물엿 2g , 깨 2g', '["통마늘","마카다미아","호두","아몬드","캐슈넛","땅콩","대두유","흑마늘진액","간장","물엿","깨"]'::jsonb, ARRAY['fc6e31ce-388e-45cd-956b-b238b9134eb1','7651578f-1206-499d-a04c-15f034d4cae2','52ba316f-8e7f-415f-8079-9a9d674c9adf','10a4a38c-376d-461d-b126-f7471d617e99','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','f175019d-5a93-4cd4-aabc-e7e79445f15a','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"통마늘과 견과류들은 먹기 좋은 크기로 자른다.","imageUrl":null},{"step":2,"text":"흑마늘 진액과 간장, 물엿, 물을 넣어 흑마늘 소스를 만든다.","imageUrl":null},{"step":3,"text":"대두유를 두르고 마늘을 팬에 노릇하게 구워준다.","imageUrl":null},{"step":4,"text":"구워진 마늘에 각종 견과류를 넣어 볶는다.","imageUrl":null},{"step":5,"text":"소스를 넣어 조린다.","imageUrl":null},{"step":6,"text":"그릇에 담고 깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200317/20200317113538_1584412538874.JPG', 179.2, 15.1, 6.3, 10.4, 120.2),
  ('3198', '고구마 찰 빵', '기타', ' 쌀가루 120g, 타피오카 전분 80g, 비트가루 15g, 물 140g, 르뱅 발효종 160g, 소금 2g, 올리브유 25g,
  고구마 30g, 생크림 10g, 김치 70g, 양파30g , 기름5g', '["쌀가루","타피오카 전분","비트가루","물","르뱅 발효종","소금","올리브유","고구마","생크림","김치","양파","기름"]'::jsonb, ARRAY['4cb11562-015f-4ab5-969f-0ea8483a0b42','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','af187077-b7f6-4b0e-9e99-f844f6359ac2','133f214e-50f4-431d-af36-d97f6c9d4f9b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742']::uuid[], '[{"step":1,"text":"(속재료) 고구마는 쪄서 으깬 후 생크림을 넣어 부드러운 무스를 만든다.\r\n 양파와 김치는 다지고, 기름 두른 팬에 양파를 볶아 단맛을 낸 다음 김치를 볶아 볶음 김치를 만든다.","imageUrl":null},{"step":2,"text":"반죽재료를 모두 넣고 1단으로 믹싱한 후 올리브유를 넣고 최종단계 직전까지 믹싱한다.","imageUrl":null},{"step":3,"text":"1차 발효 후에 반죽을 각 100g씩 총 3개로 분할하여 둥글리기 한 후 랩을 덮어 중간발효(10분)를 해준다.","imageUrl":null},{"step":4,"text":"반죽에 고구마 무스 ,볶음김치을 넣어 싼 후 고구마 모양으로 만들어 준다.\r\n★이음새가 벌어지면 구우면서 반죽이 터져지니 꼼꼼히 붙여주세요.","imageUrl":null},{"step":5,"text":"팬닝 후 2차 발효(30분)를 한다.","imageUrl":null},{"step":6,"text":"윗불 160℃, 아랫불 180℃에서 15분 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202052349_1612254229383.jpg', 241, 39.76, 6.35, 6.27, 4.16),
  ('2965', '브로콜리견과류복음', '반찬', ' 브로콜리 70g, 아몬드슬라이스 5g, 캐슈넛 10g
, 무염버터 10g, 소금 0.3g', '["브로콜리","아몬드슬라이스","캐슈넛","무염버터","소금"]'::jsonb, ARRAY['9bf64924-ce53-42bb-849e-7294416e95d6','52ba316f-8e7f-415f-8079-9a9d674c9adf','10a4a38c-376d-461d-b126-f7471d617e99','7aabd532-361f-4240-aa33-6bfa1be4bc4e','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"끓는 물에 한 입 크기로 썬 브로콜리를 데친다.","imageUrl":null},{"step":2,"text":"팬에 아몬드슬라이스, 캐슈넛을 굽는다.","imageUrl":null},{"step":3,"text":"팬에 무염버터를 녹인다.","imageUrl":null},{"step":4,"text":"버터가 녹으면 브로콜리를 넣어 불향이 나도록 볶는다.","imageUrl":null},{"step":5,"text":"구운 견과류를 넣어 볶다가 소금으로 간한다.","imageUrl":null},{"step":6,"text":"그릇에 담아 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306034924_1678085364484.jpg', 131.3, 5.7, 4.1, 10.2, 5.3),
  ('3014', '유린기', '반찬', ' 닭다리살(110g), 양상추(25g), 그린치커리(5g), 라디치오(5g), 홍고추(5g), 청양고추(5g), 대파(5g), 무순(3g), 마늘(1g), 생강(1g), 식용유(3g)
, 식초(5g), 저염간장(5g), 레몬즙(2g), 설탕(1g), 물(5g)
, 옥수수전분(5g)', '["닭다리살","양상추","그린치커리","라디치오","홍고추","청양고추","대파","무순","마늘","생강","식용유","식초","저염간장","레몬즙","설탕","물","옥수수전분"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','1389717e-81e4-4350-96d4-d627d851aa10','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','f09d1d41-602a-441c-a7bc-520311490ceb','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','a7a59e81-de3d-4893-b56a-b2218732a25b','6c285c60-022a-4a00-b172-87df97f16a2f','f175019d-5a93-4cd4-aabc-e7e79445f15a','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b','6613d1d9-80a2-4ce4-9d3d-647203197e53']::uuid[], '[{"step":1,"text":"양상추와 그린치커리, 라디치오는 먹기 좋은 크기로 찢고, 고추는 잘게 다진다.","imageUrl":null},{"step":2,"text":"대파와 생강, 마늘은 곱게 다지고, 팬에 식용유를 두른 뒤 볶는다.","imageUrl":null},{"step":3,"text":"소스 재료를 넣어 약한 불에서 5분 정도 끓인다.","imageUrl":null},{"step":4,"text":"소스를 식힌 뒤 잘게 썬 고추를 섞는다.","imageUrl":null},{"step":5,"text":"닭다리살에 옥수수전분을 묻히고, 팬에 식용유를 두른 뒤 노릇하게 굽는다.","imageUrl":null},{"step":6,"text":"그릇에 손질한 채소를 깔고, 구운 닭다리살을 올린 뒤 소스와 무순을 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309024736_1678340856988.jpg', 173.3, 7.3, 11.3, 11, 148.2),
  ('3189', '단호박 호밀빵', '기타', ' 통밀가루 200g, 강력분 200g, 전립분 40g, 소금 15g, 드라이이스트 5g, 물 150ml, 베이킹파우더 10g
 단호박 20g, 참깨 10g', '["통밀가루","강력분","전립분","소금","드라이이스트","물","베이킹파우더","단호박","참깨"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b','325279ee-6de6-4d84-96a0-16af87dfdbc6','98d652af-a6d6-440c-9653-e22fc5d47d88','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"(속재료) 단호박은 쪄서 먹기 좋은 크기로 썰어둔다.","imageUrl":null},{"step":2,"text":"통밀가루와 강력분, 전립분, 물, 소금을 섞어 5℃에서 반나절동안 1차 발효를 시킨다.","imageUrl":null},{"step":3,"text":"반죽을 썰어 모양을 잡고, 중간발효를 15분동안 한다.","imageUrl":null},{"step":4,"text":"반죽 가운데에 썰은 단호박과 참깨를 넣고 가볍게 접어서 말아 면포에 올린다.","imageUrl":null},{"step":5,"text":"굽기 전에 쿠프(칼집내기)를 한다.","imageUrl":null},{"step":6,"text":"230℃ 로 예열한 오븐에 넣고 스팀 후 210℃에서 25분 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042050_1611904850936.jpg', 271, 53.05, 10.59, 1.86, 1.83),
  ('3193', '미숫가루 스콘', '기타', '버터 40g, 박력분 90g, 강력분 90g, 미숫가루 70g, 베이킹파우더 10g, 우유 66g, 달걀 50g(1개), 건크랜베리 20g, 호두 20g', '["버터","박력분","강력분","미숫가루","베이킹파우더","우유","달걀","건크랜베리","호두"]'::jsonb, ARRAY['7aabd532-361f-4240-aa33-6bfa1be4bc4e','aab3b0b9-d346-4697-a1c8-1b1530153788','0b0eef9f-2fa0-4eb5-b1c4-5fc82d28a393','325279ee-6de6-4d84-96a0-16af87dfdbc6','e937397f-54e2-49df-997a-f393c58360be','c7d438a6-34d6-423f-905d-446b839e2f39','7651578f-1206-499d-a04c-15f034d4cae2']::uuid[], '[{"step":1,"text":"체 친 강력분, 박력분, 미숫가루, 베이킹파우더와 버터를 카드를 이용해 잘게 잘라 섞는다.\r\n★ 자르듯이 섞어야 글루텐이 생기는 것을 최소화 해, 바삭한 질감을 얻을 수 있어요.","imageUrl":null},{"step":2,"text":"계란과 우유를 섞어 넣고 카드로 잘라 주듯이 섞는다.","imageUrl":null},{"step":3,"text":"가루가 약간 보일 때쯤 건크랜베리와 호두를 넣어 같이 반죽한다.","imageUrl":null},{"step":4,"text":"뭉쳐진 반죽을 비닐에 싸서 냉장고에서 1시간 이상 휴지시킨다.","imageUrl":null},{"step":5,"text":"휴지시킨 반죽을 밀대로 밀어주고 여러 겹 쌓이도록 3접절이를 5회 정도 해준 후 카드로 일정하게 자른다.","imageUrl":null},{"step":6,"text":"오븐팬에 놓고 겉면 코팅을 위해 계란물을 얇게 발라준 후 180℃로 예열된 오븐에서 20분 정도 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129045232_1611906752043.jpg', 376, 55.8, 9.53, 12.73, 8.1),
  ('3199', '고구마 공갈빵', '기타', ' 강력분 300g, 이스트 6g, 소금 4g, 버터 10g, 물 170ml 
 고구마 3~4개, 우유20g', '["강력분","이스트","소금","버터","물","고구마","우유"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','325279ee-6de6-4d84-96a0-16af87dfdbc6','2cf0c12b-f248-4012-8f53-303c730a7b3d','7aabd532-361f-4240-aa33-6bfa1be4bc4e','94786475-832c-4f97-aab7-bf6fbbe2236b','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','e937397f-54e2-49df-997a-f393c58360be']::uuid[], '[{"step":1,"text":"(속재료) 고구마를 삶아서 껍질을 제거하고 우유를 넣어가며 으깨서 부드러운 무스 상태로 만든다.\r\n★ 고구마를 물에 삶으면 수분이 많아 우유량을 조절해야 해요.","imageUrl":null},{"step":2,"text":"버터를 제외한 모든 반죽 재료를 넣고 클린업 단계까지 믹싱하다가 버터를 넣어 최종단계까지 믹싱한다.","imageUrl":null},{"step":3,"text":"반죽은 처음 부피의 2배 정도 되도록 1차 발효하여 50g씩 분할하여 둥글리기 한 다음 중간 발효(10-15분)한다.","imageUrl":null},{"step":4,"text":"중간 발효가 끝난 반죽은 납작하게 펴고 만들어 놓은 고구마무스를 넣어 동그란 모양으로 일정하게 만든 후 팬닝한다.","imageUrl":null},{"step":5,"text":"팬닝된 반죽을 호떡처럼 윗면을 살짝 눌러준다.","imageUrl":null},{"step":6,"text":"190℃에서 15분 정도 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053118_1612254678493.jpg', 277, 56.14, 8.73, 1.92, 4.46),
  ('3200', '검은콩 크림빵', '기타', '강력분 300g, 물 250ml, 이스트 8g,  호밀가루 50g, 검은콩가루 24g, 올리브유 4g,호두 50g, 크랜베리 24g,
 불린 검은콩 300g ,우유 200g , 달걀 50g(1개) ,소금 3g', '["강력분","물","이스트","호밀가루","검은콩가루","올리브유","호두","크랜베리","불린 검은콩","우유","달걀","소금"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','94786475-832c-4f97-aab7-bf6fbbe2236b','325279ee-6de6-4d84-96a0-16af87dfdbc6','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','7651578f-1206-499d-a04c-15f034d4cae2','1c1e5578-1128-45a4-bcaf-aae79de3639e','e937397f-54e2-49df-997a-f393c58360be','c7d438a6-34d6-423f-905d-446b839e2f39','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"(속재료) 물에 불린 검은 콩을 30-40분 정도 삶은 다음 콩과 물을 분리시켜 식힌다. 식은 검은콩에 우유, 계란, 소금을 넣고 믹서에 갈고 끓여 검은콩 크림을 만든다. 이때 검은콩 물로 농도를 맞춘다.","imageUrl":null},{"step":2,"text":"호두, 크랜베리를 제외한 모든 재료를 섞어 한 덩어리가 되면 호두와 크랜베리를 넣어 밖으로 빠져 나오지 않게 잘 넣어가며 반죽한다.","imageUrl":null},{"step":3,"text":"처음 부피의 2배 정도 부풀게 1차 발효를 하고 발효가 끝나면 반죽을 6개로 분할하여 둥글리기하여 중간 발효한다.","imageUrl":null},{"step":4,"text":"중간 발효한 반죽을 공기를 빼주고 양끝을 접어 바게트 모양으로 만들어 주고 팬에 3개씩 팬닝한다.","imageUrl":null},{"step":5,"text":"\"윗불 180℃, 아랫불 160℃에서 약 20-30분정도 구워 준 뒤 냉각팬에 옮겨 식힌다.\r\n★팬에 크기에 따라 2회로 나눠 구워요.\"","imageUrl":null},{"step":6,"text":"식은 빵을 반으로 갈라 검은콩크림을 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202053932_1612255172900.jpg', 233, 37.02, 10.98, 3.47, 4.69),
  ('3229', '오이 소르베', '후식', '오이(100g), 셀러리 줄기(15g), 요거트(60g), 과일(20g), 라임즙(5g), 아가베 시럽(5g)', '["오이","셀러리 줄기","요거트","과일","라임즙","아가베 시럽"]'::jsonb, ARRAY['9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','bb41a88a-ea2b-4830-876d-91fe7f640296']::uuid[], '[{"step":1,"text":"오이는 껍질을 제거한 뒤 큼직하게 썰고, 셀러리는 필러로 겉껍질을 벗겨 큼직하게 썬다.","imageUrl":null},{"step":2,"text":"손질한 오이와 셀러리에 양념을 넣어 믹서에 곱게 간다.","imageUrl":null},{"step":3,"text":"면포에 간 오이와 셀러리를 부은 뒤 즙만 짠다.","imageUrl":null},{"step":4,"text":"오이셀러리 즙을 밀폐 용기에 넣어 냉동실에서 3시간 이상 얼린다.","imageUrl":null},{"step":5,"text":"요거트에 얼린 오이소르베를 얹고 과일을 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20221208/20221208044201_1670485321757.jpg', 65.4, 8.3, 3.7, 1.9, 34.7),
  ('3237', '리코타치즈 카프레제', '후식', '방울토마토(100g), 우유(370㎖), 레몬즙(20g), 발사믹식초(10g), 레몬즙(1g), 올리브유(10g)', '["방울토마토","우유","레몬즙","발사믹식초","올리브유"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','e937397f-54e2-49df-997a-f393c58360be','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','6c285c60-022a-4a00-b172-87df97f16a2f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"냄비에 우유(370㎖)를 넣어 센 불로 올린 뒤 가장자리가 끓어오르면 레몬즙(20g)을 넣어 몽글해질 때까지 젓는다.","imageUrl":null},{"step":2,"text":"물에 적신 면포에 끓인 우유를 넣고 물기를 제거해 리코타치즈를 만든다.","imageUrl":null},{"step":3,"text":"냄비에 발사믹식초(10g), 레몬즙(1g)을 넣어 2분간 끓이다가 올리브유(10g)를 넣어 섞은 뒤 불을 꺼 발사믹 드레싱을 만든다.","imageUrl":null},{"step":4,"text":"방울토마토는 반으로 썰고, 굳힌 리코타치즈는 한입 크기로 만든다.","imageUrl":null},{"step":5,"text":"그릇에 방울토마토와 리코타치즈를 올리고 발사믹 드레싱을 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310040853_1615360133030.jpg', 222.7, 9, 4.7, 18.6, 13.9),
  ('3238', '연두부 카프레제', '후식', '깻잎(2장), 양파(20g), 방울토마토(5개=50g), 연두부(100g), 두부(100g), 다진 마늘(10g), 치즈(40g), 간장(8g), 올리브유(30g), 참기름(15g)', '["깻잎","양파","방울토마토","연두부","두부","다진 마늘","치즈","간장","올리브유","참기름"]'::jsonb, ARRAY['3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','4566cac5-9166-4c0d-906a-bfc7360f8f5b','fc6e31ce-388e-45cd-956b-b238b9134eb1','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','f175019d-5a93-4cd4-aabc-e7e79445f15a','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"방울토마토는 3등분하고, 깻잎과 양파는 곱게 다진다.","imageUrl":null},{"step":2,"text":"연두부와 두부를 크림 형태가 될 때까지 으깬다.","imageUrl":null},{"step":3,"text":"다진 깻잎과 양파에 깻잎 드레싱 재료를 넣어 고루 섞는다.","imageUrl":null},{"step":4,"text":"중간 불로 달군 팬에 다진 마늘을 볶아 마늘 플레이크를 만든다.","imageUrl":null},{"step":5,"text":"그릇에 연두부 크림과 방울토마토, 치즈를 올린다.","imageUrl":null},{"step":6,"text":"깻잎 드레싱을 뿌리고 마늘 플레이크를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310045858_1615363138551.jpg', 309.3, 12.3, 17.5, 21.1, 279.4),
  ('3239', '연두부 토마토', '일품', '연두부(70g), 방울토마토(6~7개=50g), 스트링치즈(40g), 어린잎채소(약간), 발사믹식초(5g), 사과(150g), 사과주스(50g), 플레인 요거트(30g)', '["연두부","방울토마토","스트링치즈","어린잎채소","발사믹식초","사과","사과주스","플레인 요거트"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','6c285c60-022a-4a00-b172-87df97f16a2f','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','bb41a88a-ea2b-4830-876d-91fe7f640296']::uuid[], '[{"step":1,"text":"믹서에 사과와 사과주스를 넣고 곱게 간 뒤 플레인 요거트를 섞어 사과드레싱을 만든다.","imageUrl":null},{"step":2,"text":"연두부는 9cm 크기로 썬 뒤 중앙 부분을 파낸다.","imageUrl":null},{"step":3,"text":"방울토마토와 스트링치즈는 굵게 다진 뒤 사과드레싱에 버무린다.","imageUrl":null},{"step":4,"text":"버무려진 방울토마토와 스트링치즈로 연두부 속을 채운 뒤 사과드레싱을 올린다.","imageUrl":null},{"step":5,"text":"그릇에 발사믹 식초를 바른 뒤 속 채운 연두부를 올리고 어린잎채소를 곁들인다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeNsKgD-bA', 110.1, 7.6, 8.3, 5.1, 46.9),
  ('3261', '들깨삼겹살과 참외쌈장', '반찬', ' 삼겹살(200g), 참외(중간 크기 1개), 영양부추(50g), 들깻가루(3Ts), 마늘(5쪽), 통후추(1ts), 저염 된장(3Ts), 다진 양파(2ts), 다진 마늘(1ts), 참깨(1Ts), 참기름(2Ts), 다진 청고추(1ts), 다진 홍고추(1ts), 고춧가루(2ts), 다진 파(1ts), 들깻가루(4Ts), 사과즙(2Ts), 견과류(5Ts)', '["삼겹살","참외","영양부추","들깻가루","마늘","통후추","저염 된장","다진 양파","다진 마늘","참깨","참기름","다진 청고추","다진 홍고추","고춧가루","다진 파","사과즙","견과류"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','7dd9d8bc-46ee-40cb-974c-6fb77702e323','058648c3-fd8e-476d-952f-b15dc67f1877','184687ba-0cba-4fec-bb21-33fe300c2073','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','392236b1-82e9-4e38-bd12-6a53b80bf463','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482','30b5d53c-d247-4f04-9b50-c0f728e65cf9','84104c49-0af4-4323-a56b-b67002a422d9','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"냄비에 물(3컵)과 양념을 넣어 5분간 끓이고, 삼겹살을 넣어 중간 불로 15분간 끓인다.","imageUrl":null},{"step":2,"text":"참외(½개)는 껍질과 씨를 제거한 뒤 곱게 다진다.","imageUrl":null},{"step":3,"text":"다진 참외에 견과류와 저염쌈장 재료를 넣어 고루 섞는다.","imageUrl":null},{"step":4,"text":"영양부추는 한입 크기로 자르고, 참외(½개)는 씨를 제거한다.","imageUrl":null},{"step":5,"text":"그릇에 영양부추를 깔고, 삼겹살을 가지런히 올린다.","imageUrl":null},{"step":6,"text":"씨를 제거한 참외에 참외 저염쌈장을 담아 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9W9R', 491.8, 9.4, 16.4, 43.2, 893.9),
  ('3264', '돼지고기 포두부 파스타', '기타', ' 양파(½개), 마늘(6~7쪽), 대파(1대), 다진 돼지고기(400g), 두부면(2팩=200g), 새우(¾컵), 닭육수(5컵), 청양고추(2개), 고추장(0.5Ts), 후춧가루(0.8Ts), 식초(1.5Ts), 올리브유(10Ts), 고춧가루(1Ts)', '["양파","마늘","대파","다진 돼지고기","두부면","새우","닭육수","청양고추","고추장","후춧가루","식초","올리브유","고춧가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','70e914d4-0d03-4202-8b66-81bd8499aa08','6f10b4ad-53a2-4a07-ba89-19a6b074373d','a4c37075-c03b-47bb-8aed-5e907620f5d2','30b5d53c-d247-4f04-9b50-c0f728e65cf9','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6c285c60-022a-4a00-b172-87df97f16a2f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','84104c49-0af4-4323-a56b-b67002a422d9']::uuid[], '[{"step":1,"text":"양파는 3mm 두께로 채 썰고, 마늘은 납작 썰고, 대파와 청양고추는 어슷 썬다.","imageUrl":null},{"step":2,"text":"다진 돼지고기에 고추장과 후춧가루 (0.3Ts)를 넣어 고루 섞은 뒤 10분간 재운다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 올리브유(3Ts)를 두르고, 다진 돼지고기와 고춧가루를 넣어 돼지고기의 겉면이 하얗게 변할 때까지 볶는다.","imageUrl":null},{"step":4,"text":"올리브유(7Ts)에 납작 썬 마늘, 대파, 양파, 건새우, 후춧가루(0.3Ts)를 넣고 마늘이 노릇해질 때까지 볶는다.","imageUrl":null},{"step":5,"text":"두부면과 닭육수(½컵)를 넣은 뒤 육수가 졸아들 때까지 볶고, 후춧가루(0.2Ts)와 청양고추를 넣어 1분간 볶는다.","imageUrl":null},{"step":6,"text":"그릇에 담고 볶은 돼지고기와 식초에 재운 양파를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9XCr', 459.4, 9.9, 35.6, 30.8, 211.8),
  ('3296', '단호박 양파잼 샌드위치', '기타', ' 양파(3개), 미니 단호박(2개), 삶은 달걀(3개), 우유(½컵), 식빵(4장), 슬라이스 체더치즈(2장), 말린 자두(½컵), 청상추(2장), 아몬드 슬라이스(⅓컵), 화이트와인(⅓컵), 꿀(2Ts), 소금(0.3Ts), 후춧가루(약간)', '["양파","미니 단호박","삶은 달걀","우유","식빵","슬라이스 체더치즈","말린 자두","청상추","아몬드 슬라이스","화이트와인","꿀","소금","후춧가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','98d652af-a6d6-440c-9653-e22fc5d47d88','c7d438a6-34d6-423f-905d-446b839e2f39','e937397f-54e2-49df-997a-f393c58360be','a18f6f83-06b8-473c-88b3-c2c8f2a7d0fc','52ba316f-8e7f-415f-8079-9a9d674c9adf','e16eaf50-ebd3-4933-a774-3ce6fc92593f','286d1783-cd34-4aae-ac8b-006529ec8bc5','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"양파는 얇게 채 썰고, 단호박은 껍질과 씨를 제거한 뒤 큼직하게 썰고, 말린 자두는 굵게 다지고, 청상추는 깨끗하게 씻는다.","imageUrl":null},{"step":2,"text":"종이포일 위에 단호박을 올리고, 식용유(1Ts)를 두른 뒤 180℃로 예열한 오븐에서 15분간 구워 꺼내고, 삶은 달걀의 노른자는 체에 거르고, 흰자는 곱게 다진다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 식용유(2Ts)를 두르고, 화이트와인을 조금씩 넣으며 양파가 갈색이 될 때까지 볶아 양파잼을 만든다.","imageUrl":null},{"step":4,"text":"구운 단호박은 한 김 식힌 뒤 체에 곱게 거르고, 달걀노른자, 흰자, 우유, 꿀, 소금, 후춧가루를 넣어 고루 섞어 단호박샐러드를 만든다.","imageUrl":null},{"step":5,"text":"약한 불로 달군 마른 팬에 아몬드 슬라이스를 넣어 노릇하게 볶는다.","imageUrl":null},{"step":6,"text":"식빵(1장)에 단호박샐러드, 청상추, 슬라이스 체더치즈를 올리고, 다른 식빵(1장)에 양파잼을 넉넉하게 바른 뒤 덮고, 삼각형으로 잘라 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9l5l', 287, 41.8, 10.5, 8.6, 489.2),
  ('3201', '시금치크림치즈 빵', '기타', ' 통밀가루 50g, 강력분 200g, 인스턴트 드라이 이스트 3g, 사과종 45ml, 물 120ml, 소금 2g, 달걀 50g(1개), 올리브유 15g, 시금치 소량, 말린 방울토마토 4~5개
 시금치 50g, 다진 마늘 3g,  볶음 참깨 60g, 올리브유 8g, 소금 소량, 후추 소량, 크림치즈 100g', '["통밀가루","강력분","인스턴트 드라이 이스트","사과종","물","소금","달걀","올리브유","시금치 소량","말린 방울토마토","시금치","다진 마늘","볶음 참깨","소금 소량","후추 소량","크림치즈"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d','c7d438a6-34d6-423f-905d-446b839e2f39','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','9a7f4da6-531b-4478-89ff-d73beafcad1b','fc6e31ce-388e-45cd-956b-b238b9134eb1','b42c6eac-0afb-4d87-8942-ed1a9c294b09']::uuid[], '[{"step":1,"text":"(속재료) 시금치, 다진 마늘, 볶은 참깨, 올리브유, 소금, 후추를 블랜더로 갈아 시금치 페스토를 만들고 크림치즈와 섞는다.","imageUrl":null},{"step":2,"text":"물, 계란, 소금, 올리브유, 사과종, 드라이 이스트와 체 친 가루류를 넣고 한 덩이가 되도록 반죽한 뒤 시금치를 작게 잘라 넣어 섞는다.","imageUrl":null},{"step":3,"text":"매끈한 반죽이 되면 8등분 하여 둥글리기를 하고 15분간 중간 발효한다.","imageUrl":null},{"step":4,"text":"중간 발효가 끝난 반죽을 납작하게 펴고 안에 시금치 필링을 넣어 잘 봉합한 뒤 팬에 놓고 살짝 눌러준다.","imageUrl":null},{"step":5,"text":"\"중앙에 말린 방울토마토를 얹어 30분간 2차 발효 한다.\r\n★방울토마토를 반으로 잘라 100℃ 오븐에 1시간 구워 사용했어요.\"","imageUrl":null},{"step":6,"text":"180℃로 예열한 오븐에 15분간 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210202/20210202054852_1612255732266.jpg', 303, 36.07, 9.2, 13.54, 2.28),
  ('2966', '무말랭이김치', '반찬', '무말랭이 10g, 식초 30g, 설탕 25g, 레몬 8g, 당근 5g, 오이 5g, 피클링스파이스 5g, 물 100g', '["무말랭이","식초","설탕","레몬","당근","오이","피클링스파이스","물"]'::jsonb, ARRAY['6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','e38c12a7-43cb-421a-a36e-7ef0d32517fa','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"무말랭이를 물에 불린다.","imageUrl":null},{"step":2,"text":"식초, 설탕, 피클링스파이스, 물을 넣고 끓인다.","imageUrl":null},{"step":3,"text":"끓인 물을 식힌다.","imageUrl":null},{"step":4,"text":"레몬, 당근, 오이를 적당한 크기로 자른다.","imageUrl":null},{"step":5,"text":"4를 3에 넣어 하루 이상 숙성시킨다.","imageUrl":null},{"step":6,"text":"보기 좋게 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408105718_1554688638823.jpg', 10.86, 2.56, 0.14, 0, 1.85),
  ('3015', '코울슬로샐러드', '반찬', ' 양배추(30g), 양파(10g), 적파프리카(3g), 청피망(3g)
, 마요네즈(5g), 설탕(1g), 식초(0.5g)', '["양배추","양파","적파프리카","청피망","마요네즈","설탕","식초"]'::jsonb, ARRAY['fd4254d4-2691-47e1-9367-c2b820ef8d00','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','df459e6f-3515-45d5-8c9a-9d37b6249379','549c7365-28e9-491f-9040-412558f93a5c','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"양배추와 양파, 적파프리카, 청피망을 깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"양배추와 양파를 잘게 썬다.","imageUrl":null},{"step":3,"text":"적파프리카와 청피망은 씨를 제거하고 잘게 썬다.","imageUrl":null},{"step":4,"text":"마요네즈드레싱 재료를 고루 섞는다.","imageUrl":null},{"step":5,"text":"볼에 썰어둔 채소를 담는다.","imageUrl":null},{"step":6,"text":"마요네즈드레싱을 넣고 버무려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308020951_1678252191936.jpg', 44.1, 4.2, 0.6, 2.8, 26.8),
  ('3062', '마들깨미역국', '국&찌개', '건미역 4g, 마 40g, 깐들깨가루 17g, 건다시마 1g, 참기름 2.5g, 마늘 2.5g, 물 300ml', '["건미역","마","깐들깨가루","건다시마","참기름","마늘","물"]'::jsonb, ARRAY['6565cc3a-c3d6-45b5-a7fb-05a3c03015bf','a988ffbb-92c3-4c68-8cea-a2f10c329015','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','0c0ade94-cfd8-4104-b44c-40e942cac482','fc6e31ce-388e-45cd-956b-b238b9134eb1','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"다시 육수를 만들어 준다.","imageUrl":null},{"step":2,"text":"건미역은 불려 잘게 썰어준다.","imageUrl":null},{"step":3,"text":"마는 껍질을 제거한 후 깍둑 썰기하여 준비한다.","imageUrl":null},{"step":4,"text":"참기름을 두르고 미역과 마늘을 볶다가 육수를 부어 끓인다.","imageUrl":null},{"step":5,"text":"끓어오른 미역국에 마를 넣어 익혀준다.","imageUrl":null},{"step":6,"text":"들깨가루를 넣어 한소끔 끓여낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200309/20200309012227_1583727747787.JPG', 161.9, 13.1, 6.8, 9.2, 173.6),
  ('3064', '바지락맑은국', '국&찌개', ' 바지락(60g), 팽이버섯(20g), 홍고추(5g), 쑥갓(2g)
, 다시마(5g), 청양고추(3g), 무(10g), 대파(5g), 물(300g)', '["바지락","팽이버섯","홍고추","쑥갓","다시마","청양고추","무","대파","물"]'::jsonb, ARRAY['b6047d76-6c94-4757-b1d1-9175aea0c84a','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','30b5d53c-d247-4f04-9b50-c0f728e65cf9','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','f80c9a7d-1510-44e2-a82b-28b9f684e191','4b410642-7bf9-45ad-9055-e7d9a34edaa1','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"물에 다시마, 청양고추, 대파, 한 입 크기로 썬 무를 넣고 끓인다.","imageUrl":null},{"step":2,"text":"육수가 끓으면 청양고추와 다시마를 건진다.","imageUrl":null},{"step":3,"text":"해감한 바지락을 넣고 끓인다.","imageUrl":null},{"step":4,"text":"팽이버섯은 밑동을 자른 뒤 적당히 가르고, 홍고추는 어슷 썰고, 쑥갓은 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":5,"text":"국에 팽이버섯을 넣고 끓인다.","imageUrl":null},{"step":6,"text":"홍고추와 쑥갓을 넣고 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307040515_1678172715096.jpg', 9.9, 0.8, 1.5, 0.1, 82.7),
  ('3158', '통배추 겉절이', '반찬', ' 통배추(25g), 쪽파(1g), 마늘(1g), 생강(0.5g)
, 소금(0.1g), 홍시(1g), 고춧가루(1g), 젓갈(1g), 통깨(1g), 참기름(0.5g)', '["통배추","쪽파","마늘","생강","소금","홍시","고춧가루","젓갈","통깨","참기름"]'::jsonb, ARRAY['4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','2cf0c12b-f248-4012-8f53-303c730a7b3d','2db5cf59-b4ac-4d7b-8e13-68d143e5f34a','84104c49-0af4-4323-a56b-b67002a422d9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"배추는 연한 잎으로 골라 한 장씩 떼어 길게 갈라놓는다.","imageUrl":null},{"step":2,"text":"배추에 소금을 뿌려 절인다.","imageUrl":null},{"step":3,"text":"쪽파는 4cm 길이로 썰고, 마늘과 생강은 다진다.","imageUrl":null},{"step":4,"text":"고춧가루에 홍시를 으깨서 나머지 양념을 섞는다.","imageUrl":null},{"step":5,"text":"물기를 제거한 배추에 고춧가루 양념을 넣고 무친다.","imageUrl":null},{"step":6,"text":"쪽파, 통깨, 참기름을 넣고 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313025524_1678686924073.jpg', 22, 2.6, 1, 0.8, 110.2),
  ('3240', '포니언 스프', '일품', ' 감자(100g), 양파(40g), 우유(30g), 시판 크루통(7g), 파슬리가루(1g)
, 버터(5g), 소금(0.3g), 후춧가루(0.3g)', '["감자","양파","우유","시판 크루통","파슬리가루","버터","소금","후춧가루"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e937397f-54e2-49df-997a-f393c58360be','4362c386-a37c-44cd-9254-fafd74712a09','7aabd532-361f-4240-aa33-6bfa1be4bc4e','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"감자는 슬라이스하고, 양파는 채 썬다.","imageUrl":null},{"step":2,"text":"끓는 물(5컵)에 감자를 넣어 7분간 삶아 건진다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 버터를 두른 뒤 양파를 넣어 3~5분간 볶아 꺼낸다.","imageUrl":null},{"step":4,"text":"믹서에 삶은 감자와 양파, 우유를 넣어 곱게 간다.","imageUrl":null},{"step":5,"text":"냄비에 믹서에 간 재료들을 넣어 약한 불로 3분간 끓여 농도를 맞춘다.","imageUrl":null},{"step":6,"text":"소금과 후춧가루로 간을 맞춘 뒤 시판 크루통과 파슬리가루를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230313/20230313030603_1678687563726.jpg', 187.8, 24.1, 5, 7.9, 109.1),
  ('3246', '가지 탕수육', '일품', '돼지고기(70g), 두부(50g), 아삭이고추(30g), 가지(60g), 식용유(100ml), 소금(0.3g), 후춧가루(0.2g), 간장(20g), 올리고당(30g), 식초(10g), 전분(10g), 튀김가루(50g)', '["돼지고기","두부","아삭이고추","가지","식용유","소금","후춧가루","간장","올리고당","식초","전분","튀김가루"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','4566cac5-9166-4c0d-906a-bfc7360f8f5b','3e12cf79-2cde-4309-9f7c-4eccce3fde28','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f175019d-5a93-4cd4-aabc-e7e79445f15a','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','6c285c60-022a-4a00-b172-87df97f16a2f','6613d1d9-80a2-4ce4-9d3d-647203197e53','aab3b0b9-d346-4697-a1c8-1b1530153788']::uuid[], '[{"step":1,"text":"돼지고기, 두부, 아삭이고추는 잘게 다지고, 가지는 어슷하게 4등분해 가운데 칼집을 넣는다.","imageUrl":null},{"step":2,"text":"다진 돼지고기는 밑간한 뒤 다진 두부, 고추를 넣어 섞는다.","imageUrl":null},{"step":3,"text":"칼집을 넣은 가지에 밑간한 돼지고기를 채운 뒤 튀김가루를 묻힌다.","imageUrl":null},{"step":4,"text":"튀김가루를 묻힌 가지는 180℃로 예열한 식용유(100㎖)에 7~8분간 두 번 튀긴다.","imageUrl":null},{"step":5,"text":"냄비에 가지소스 재료와 물(100㎖)을 넣어 4분간 끓인다.","imageUrl":null},{"step":6,"text":"그릇에 튀긴 가지를 얹고 가지소스를 뿌린다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF8rC', 297.2, 27.2, 7.5, 17.6, 596.3),
  ('3293', '토마토소스 애호박냉파스타', '기타', ' 토마토(2개), 참외(1개), 오이(1개), 양파(½개), 마늘(3쪽), 애호박(1개), 바질잎(4장), 블랙올리브 파우더(약간), 레몬즙(1Ts), 올리브유(5Ts), 소금(0.4Ts), 페페론치노(0.3Ts), 저염 간장(0.5Ts), 식초(2Ts), 꿀(1Ts)', '["토마토","참외","오이","양파","마늘","애호박","바질잎","블랙올리브 파우더","레몬즙","올리브유","소금","페페론치노","저염 간장","식초","꿀"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','7dd9d8bc-46ee-40cb-974c-6fb77702e323','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"토마토는 꼭지를 제거하고, 열십자로 칼집을 낸 뒤 끓는 물에 30초간 데쳐 건지고, 껍질을 제거해 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"참외는 깨끗하게 씻어 2등분해 씨를 제거한 뒤 한입 크기로 썰고, 오이와 양파는 한입 크기로 썰고, 마늘은 꼭지를 제거한 뒤 4등분한다.","imageUrl":null},{"step":3,"text":"애호박은 스파이럴라이저로 썰고, 끓는 물에 30초간 데쳐 건진 뒤 한 김 식히고, 레몬즙(1Ts), 올리브유(2Ts), 소금(0.1Ts)에 버무린다.","imageUrl":null},{"step":4,"text":"믹서에 토마토, 오이, 참외, 양파, 마늘, 바질잎(3장), 페페론치노, 차가운 물(½컵)을 넣어 곱게 갈아 토마토소스를 만든다.","imageUrl":null},{"step":5,"text":"저염 간장, 식초, 꿀, 올리브유(3Ts), 소금(0.3Ts)을 넣어 한 번 더 곱게 간다.","imageUrl":null},{"step":6,"text":"그릇에 애호박면과 토마토소스를 담고, 바질잎(1장)과 블랙올리브 파우더를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9bhk', 121.7, 9.4, 2.7, 8.1, 425.3),
  ('3299', '새우채소 김치롤', '반찬', ' 김치(¼포기), 오이(1개), 파프리카(노랑, 빨강 각 1개), 깻잎(5장), 새우(2마리), 달걀물(2개 분량), 무순(⅓줌), 크래미(2줄), 식용유(0.3ts)', '["김치","오이","파프리카","깻잎","새우","달걀물","무순","크래미","식용유"]'::jsonb, ARRAY['133f214e-50f4-431d-af36-d97f6c9d4f9b','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','5e79d288-1400-4817-bd20-e5e6041821b1','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','6f10b4ad-53a2-4a07-ba89-19a6b074373d','c7d438a6-34d6-423f-905d-446b839e2f39','f09d1d41-602a-441c-a7bc-520311490ceb','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"김치는 깨끗하게 씻어 찬물에 30분간 담근 뒤 건져내고, 물기를 꼭 짠 뒤 윗동을 약간 자른다.","imageUrl":null},{"step":2,"text":"오이와 파프리카는 5cm 길이로 채 썰고, 깻잎과 무순은 깨끗하게 씻어 물기를 빼고, 크래미는 낱낱이 가른다.","imageUrl":null},{"step":3,"text":"새우는 껍질을 벗기고, 끓는 물에 익을 때까지 데쳤다 건져 길게 2등분한다.","imageUrl":null},{"step":4,"text":"약한 불로 달군 팬에 식용유를 두르고, 달걀물을 부어 지단을 부친다.","imageUrl":null},{"step":5,"text":"김발에 김치를 한 장씩 겹쳐 넓게 펼친다.","imageUrl":null},{"step":6,"text":"김치 위에 지단, 손질한 채소, 새우를 올리고, 돌돌 말아 한입 크기로 썰어 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9nfC', 121.1, 5.5, 14.2, 4.7, 526.4),
  ('3459', '떡순이 두부쌈', '일품', ',  누들 떡볶이 떡(20개, 130g), 소고기 양지(110g), 어묵(1장, 40g), 양배추(60g), 떡볶이양념파우더(30g),  쌈두부(100g), 부추(10g), 파프리카(빨간색, 노란색 각 30g), 식용유(25g), 물(150g)', '["누들 떡볶이 떡","소고기 양지","어묵","양배추","떡볶이양념파우더","쌈두부","부추","파프리카","식용유","물"]'::jsonb, ARRAY['fd4254d4-2691-47e1-9367-c2b820ef8d00','058648c3-fd8e-476d-952f-b15dc67f1877','5e79d288-1400-4817-bd20-e5e6041821b1','a7a59e81-de3d-4893-b56a-b2218732a25b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"양배추, 어묵, 파프리카를 길게 썰고 부추는 한번 데친다.","imageUrl":null},{"step":2,"text":"팬에 식용유를 살짝 두르고 어묵을 볶아 꺼내고, 같은 팬에 소고기 양지를 구워 준비한다.","imageUrl":null},{"step":3,"text":"냄비에 물과 누들 떡볶이 떡을 넣어 끓이고 떡이 익으면 건져낸다.","imageUrl":null},{"step":4,"text":"떡볶이양념파우더를 넣고 조려서 떡볶이 소스를 만든다.","imageUrl":null},{"step":5,"text":"쌈두부를 깔고 조리한 소고기 양지, 떡과 손질한 어묵, 파프리카, 양배추를 올린 후 싸서 데친 부추로 묶는다.","imageUrl":null},{"step":6,"text":"떡볶이 소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106030518_1699250718775.jpg', 517, 47.4, 32.5, 22, 566),
  ('3467', '두부샐러드 메밀김밥', '일품', ',  메밀면(생면, 166g), 오이(55g), 양파(42g), 당근(25g), 족발(200g), 달걀지단(20g),  양배추(50g), 사과(1/4개=60g), 깻잎(15g), 리코타 치즈(60g), 연두부(80g), 다진 레몬청 과육(50g), 참기름(14g), 간장(20g), 김(2장)', '["메밀면","오이","양파","당근","족발","달걀지단","양배추","사과","깻잎","리코타 치즈","연두부","다진 레몬청 과육","참기름","간장","김"]'::jsonb, ARRAY['b85df3ba-e324-47fa-b25d-d5bb552b8590','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','c7d438a6-34d6-423f-905d-446b839e2f39','fd4254d4-2691-47e1-9367-c2b820ef8d00','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','4566cac5-9166-4c0d-906a-bfc7360f8f5b','0c0ade94-cfd8-4104-b44c-40e942cac482','f175019d-5a93-4cd4-aabc-e7e79445f15a','09229cbc-4574-4002-b726-68c37345bbe9']::uuid[], '[{"step":1,"text":"당근, 양파, 깻잎은 깨끗이 씻고, 오이, 양배추, 사과는 채 썬다.","imageUrl":null},{"step":2,"text":"리코타 치즈, 연두부, 다진 레몬청 과육을 섞어 소스를 만들고 양배추, 사과와 함께 버무려 두부 리코타 샐러드를 만든다.","imageUrl":null},{"step":3,"text":"메밀면을 4분간 삶아 물기를 제거한 후 참기름, 간장을 넣어 버무린다.","imageUrl":null},{"step":4,"text":"족발은 전자레인지에 1분간 돌리고 채 썰어 준비한다.","imageUrl":null},{"step":5,"text":"김을 깔고 양념한 메밀면 → 깻잎 → 오이 → 당근 → 양파 → 두부 리코타 샐러드 → 족발 순서로 올려 말아 김밥을 만든다.","imageUrl":null},{"step":6,"text":"김밥을 먹기 좋은 크기로 썰고 달걀지단을 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20231106/20231106040351_1699254231703.jpg', 423.9, 30.2, 30.4, 20.1, 561.9),
  ('3243', '토마토채소스프와 연어소바찜', '일품', '토마토(356g), 무(6g), 당근(6g), 마늘(5g), 양파(6g), 연어(100g), 메밀면(70g), 월계수잎(2g), 소금(1g)', '["토마토","무","당근","마늘","양파","연어","메밀면","월계수잎","소금"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','f80c9a7d-1510-44e2-a82b-28b9f684e191','e38c12a7-43cb-421a-a36e-7ef0d32517fa','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','35db7cf0-556e-49d8-b6d2-f6e1b1e12e16','b85df3ba-e324-47fa-b25d-d5bb552b8590','043a9631-bb6e-42e6-9673-4943457502fb','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"토마토(100g)와 무, 당근, 마늘, 양파는 작게 썰고, 연어는 길게 2장으로 포를 뜬다.","imageUrl":null},{"step":2,"text":"믹서에 토마토(250g)를 넣어 간 뒤 체에 걸러 월계수잎과 함께 3분간 졸인다.","imageUrl":null},{"step":3,"text":"졸인 토마토에 작게 썬 토마토와 무, 당근, 마늘, 양파, 소금을 넣어 1분간 볶다가 물(250㎖)을 넣고 5분간 끓인다.","imageUrl":null},{"step":4,"text":"끓는 물(800㎖)에 메밀면을 넣어 4분간 삶아 찬물에 헹군 뒤 포 뜬 연어에 돌돌만다.","imageUrl":null},{"step":5,"text":"면포 깐 찜기에 김이 오르면 메밀면을 감싼 연어를 넣어 3분간 찐다.","imageUrl":null},{"step":6,"text":"그릇에 토마토채소스프와 연어소바찜을 담아 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF6ZH', 260, 37.2, 16.3, 5.1, 250.5),
  ('3241', '참나물무말이 물김치', '반찬', '참나물(30g), 무(20g), 레몬(1개), 설탕(10g), 사과식초(20g), 물(20㎖), 사과식초(15g), 마늘(2쪽), 홍고추(1개), 사과(½개)', '["참나물","무","레몬","설탕","사과식초","물","마늘","홍고추","사과"]'::jsonb, ARRAY['09065cd3-28cc-4a82-8b3e-5121054c7482','f80c9a7d-1510-44e2-a82b-28b9f684e191','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','94786475-832c-4f97-aab7-bf6fbbe2236b','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','c85a52b9-c3b4-4a76-951c-bb40edeb3adb']::uuid[], '[{"step":1,"text":"끓는 물(500㎖)에 참나물 줄기를 1분간 데쳐 건진 뒤 찬물에 헹군다.","imageUrl":null},{"step":2,"text":"무는 둥근 모양을 살려 얇게 썰고, 참나물 잎은 얇게 채 썰고, 레몬은 강판에 갈아 제스트를 만든다.","imageUrl":null},{"step":3,"text":"냄비에 절임물 재료와 물(40㎖)을 넣어 2분간 끓인 뒤 손질한 무를 넣어 30분간 절인다.","imageUrl":null},{"step":4,"text":"믹서에 김칫국물 재료를 넣어 간 뒤 고운체에 거른다.","imageUrl":null},{"step":5,"text":"절인 무에 채 썬 참나물 잎을 올려 돌돌 말고 데친 참나물 줄기로 묶는다.","imageUrl":null},{"step":6,"text":"그릇에 무말이와 김칫국물을 담은 뒤 레몬 제스트를 뿌린다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NeTnFJF29h', 34.4, 7.5, 0.8, 0.2, 209),
  ('2967', '소고기 무국', '국&찌개', '소고기 14g, 무 15g, 파 3g, 느타리버섯 5g, 숙주 5g, 저염간장 10g, 물 150g', '["소고기","무","파","느타리버섯","숙주","저염간장","물"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','f80c9a7d-1510-44e2-a82b-28b9f684e191','4b410642-7bf9-45ad-9055-e7d9a34edaa1','7c91e298-5ace-4242-8619-cdcc80587cd7','2647e451-e8f5-4fce-91bd-8beabb2384d8','f175019d-5a93-4cd4-aabc-e7e79445f15a','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"소고기를 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":2,"text":"무를 한입 크기로 썬다.","imageUrl":null},{"step":3,"text":"냄비에 참기름을 두르고 고기의 핏기가 없어질 때 까지 볶는다.","imageUrl":null},{"step":4,"text":"고기가 익으면 무를 넣고 투명해질 때 까지 볶는다.","imageUrl":null},{"step":5,"text":"중불에서 물을 붓고 끓으면 느타리버섯을 넣는다.","imageUrl":null},{"step":6,"text":"숙주나물과 파를 넣고 한소끔 끓이고 저염간장과 고춧가루를 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190408/20190408110212_1554688932975.jpg', 46.5, 3.42, 6.49, 0.77, 226.87)
